mapper.update:
UPDATE TBL_STOCK
SET STOCK_QTY = STOCK_QTY - #{moveQty},
    UPDT_TIME = GETDATE(),
    UPDT_USER = #{userId}
WHERE CMPY_CD = #{cmpyCd}
  AND LOC_ID = ( SELECT LOC_ID FROM　TBL_WH_LOC_M WHERE LOC_CD = #{fromLocationCd} )
  AND MTRL_CD = #{mtrlCd}
  AND STOCK_QTY >= #{moveQty}

    /* 1. 필요한 정보를 변수에 담고, 화주사 코드가 없으면 마스터에서 조회하여 보정 */
    DECLARE @TargetLocId BIGINT;
DECLARE @TargetZoneId BIGINT;
DECLARE @WhCd VARCHAR(20);
DECLARE @AgntCd VARCHAR(20) = #{agntCd};

    /* [보완] 전달받은 화주 코드가 NULL인 경우 상품 마스터에서 직접 조회 */
    IF @AgntCd IS NULL OR @AgntCd = ''
    BEGIN
    SELECT TOP 1 @AgntCd = AGNT_CD
    FROM TBL_MTRL_M
    WHERE MTRL_CD = #{mtrlCd} AND CMPY_CD = #{cmpyCd};
    END

/* 2. 목적지 로케이션 및 구역 정보 확보 */
    SELECT TOP 1 @TargetLocId = LOC_ID, @TargetZoneId = ZONE_ID, @WhCd = WH_CD
    FROM TBL_WH_LOC_M
    WHERE LOC_CD = LTRIM(RTRIM(#{toLocationCd})) AND CMPY_CD = #{cmpyCd};

    /* 3. 로케이션 검증 */
    IF @TargetLocId IS NULL
    BEGIN
    RAISERROR('목적지 로케이션을 찾을 수 없습니다.', 16, 1);
    RETURN;
    END

/* 4. MERGE 수행: 보정된 @AgntCd를 사용하여 NULL 입력 에러 방지 */
    MERGE INTO TBL_STOCK AS target
        USING (
            SELECT
                #{cmpyCd} as cmpyCd,
                @TargetLocId as loc,
                #{mtrlCd} as mtrl,
                @AgntCd as agnt
        ) AS source
        ON (target.CMPY_CD = source.cmpyCd AND target.LOC_ID = source.loc AND target.MTRL_CD = source.mtrl)
        WHEN MATCHED THEN
            UPDATE SET
                STOCK_QTY = target.STOCK_QTY + #{moveQty},
                UPDT_TIME = GETDATE(),
                UPDT_USER = #{userId}
        WHEN NOT MATCHED THEN
            INSERT (CMPY_CD, AGNT_CD, MTRL_CD, ZONE_ID, LOC_ID, STOCK_QTY, UPDT_TIME, UPDT_USER, WH_CD)
                VALUES (
                           source.cmpyCd,
                           source.agnt, /* 보정된 화주 코드 삽입 */
                           source.mtrl,
                           @TargetZoneId,
                           @TargetLocId,
                           #{moveQty},
                           GETDATE(),
                           #{userId},
                           @WhCd
                       );
